from openai import OpenAI
client = OpenAI()
def detect_tool_loop(thread_id):
    events = client.beta.threads.runs.list(
        thread_id=thread_id,
        event_types=['thread.run.step.created']
    ).data
    tool_calls = []
    for event in events[:20]:
        if 'step' in event.data:
            step = event.data['step']
            if step['step_details']['type'] == 'tool_calls':
                for tool in step['step_details']['tool_calls']:
                    tool_calls.append(tool['type'])
    if len(tool_calls) > 10 and len(set(tool_calls[-10:])) <= 2:
        return {'loop_detected': True, 'repeating_tools': tool_calls[-10:]}
    return {'loop_detected': False}

import networkx as nx
from openai import OpenAI
client = OpenAI()
def detect_function_cycles(thread_id):
    run = client.beta.threads.runs.retrieve(thread_id=thread_id)
    G = nx.DiGraph()
    events = client.beta.threads.runs.list(thread_id, limit=50).data
    for event in events:
        if 'step' in event.data and event.data['step']['type'] == 'tool_calls':
            for tool in event.data['step']['step_details']['tool_calls']:
                func_name = tool['function']['name']
                G.add_node(func_name)
                G.add_edge('assistant', func_name)
    cycles = list(nx.simple_cycles(G))
    return {'cycles_found': len(cycles) > 0, 'cycles': cycles}

import OpenAI from 'openai';
const openai = new OpenAI();

export async function detectLoopInRun(run: OpenAI.Beta.Threads.Runs.Run) {
  const events = await openai.beta.threads.runs.events.list(run.thread_id!, {
    run_id: run.id!,
  });
  const toolCalls = events.data
    .filter((e) => e.data?.step?.step_details?.type === 'tool_calls')
    .slice(0, 20)
    .map((e) => e.data.step.step_details.tool_calls[0]?.type || '');
  const recentUnique = new Set(toolCalls.slice(-10));
  const isLoop = toolCalls.length > 10 && recentUnique.size <= 2;
  return {
    loopDetected: isLoop,
    repeatingTools: Array.from(recentUnique),
    stepCount: toolCalls.length,
  };
}

