@vex.on('openai_run_complete')
def detect_tool_loops(event):
    thread_id = event['data']['thread_id']
    run = client.beta.threads.runs.retrieve(thread_id, event['data']['run_id'])

    if run.status == 'requires_action':
        step_count = len(client.beta.threads.runs.events.list(thread_id).data)
        if step_count > 15:
            vex.trigger_remediation(
                'tool_loop_detected',
                {
                    'assistant_id': run.assistant_id,
                    'step_count': step_count,
                    'action': 'cancel_and_restart'
                }
            )
            return {'status': 'loop_detected', 'action': 'cancelled'}

